import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"44. Breaks","description":"","frontmatter":{"title":"44. Breaks","eba":"Nurses and Midwives 2024-2028","topics":["leave","hours","breaks","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/44-breaks.md","filePath":"ebas/nurses-midwives/hours-of-work/44-breaks.md"}'),o={name:"ebas/nurses-midwives/hours-of-work/44-breaks.md"};function n(i,e,l,d,p,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_44-breaks" tabindex="-1">44. Breaks <a class="header-anchor" href="#_44-breaks" aria-label="Permalink to &quot;44. Breaks&quot;">​</a></h1><p><strong>44.1</strong> Meal breaks</p><p><strong>(a)</strong> An Employee will be entitled to an unpaid meal break of not less than 30 minutes and not more than 60 minutes.</p><p><strong>(b)</strong> Employees are entitled to leave the ward/unit area during their meal break.</p><p><strong>(c)</strong> An Employee unable to take a meal break (including where an Employee is not entitled to leave the ward/unit area for their meal break) will be paid for the meal break as time worked at their ordinary rate plus 50%.</p><p><strong>(d)</strong> Meal break not taken - escalation</p><p>Each Employer will describe, in writing, the steps to be taken where an Employee does not take a scheduled meal break to ensure that:</p><p><strong>(i)</strong> wherever possible, the meal break is rescheduled and taken during the shift; and</p><p><strong>(ii)</strong> consideration is given to what caused the Employee to miss the scheduled meal break and whether any additional action is required to address those causes to reduce the likelihood of recurrence.</p><p><strong>(e)</strong> Crib time</p><p>Where Employees are regularly unable to take their meal breaks (including because the Employee is not entitled to leave the ward for their meal break), a &#39;crib time&#39; arrangement will operate. The crib time arrangement entitles an Employee to a paid meal interval of not less than 20 minutes to commence between three hours and five hours of duty.</p><p><strong>44.2</strong> Tea breaks</p><p>Every Employee will be entitled to two paid ten minute tea breaks each shift at a time suitable to the Employer which will be counted as time worked.</p><p><strong>44.3</strong> Clothing change</p><p>Where an Employee performs a role that requires changing into and/or out of specific clothes that are necessary to perform work - such as theatre - or is required to wear full PPE (i.e. mask, face shield, and gown), the Employer will ensure there are arrangements providing that this occurs during paid time.</p><p>Plain language terms: meal break, lunch break, tea break, rest breaks.</p>',16)])])}const c=a(o,[["render",n]]);export{u as __pageData,c as default};
